-- Backfill job_invoices.paid_date from BuilderTrend (run AFTER the ALTER below).
-- Idempotent — safe to re-run.
BEGIN;
CREATE TEMP TABLE _bt_pd (bt_invoice_id bigint, paid_date date) ON COMMIT DROP;
UPDATE job_invoices ji SET paid_date = s.paid_date
  FROM _bt_pd s WHERE ji.bt_invoice_id = s.bt_invoice_id;
COMMIT;
